window.WebActRoutes={routes:{home:"/",contact:"/contact/index.html",portfolio:"/about/portfolio.html",pricing:"/pricing/index.html",industries:"/industries/index.html",privacy:"/privacy-policy/index.html",terms:"/terms/index.html",sitemap:"/sitemap.xml"},url:function(i){return this.routes[i]||"/"},currentPath:function(){return window.location.pathname.replace(/\/$/,"/index.html")},section:function(){var i=this.currentPath();return 0===i.indexOf("/design/")?"design":0===i.indexOf("/marketing/")?"marketing":0===i.indexOf("/digital-ads/")?"digital-ads":0===i.indexOf("/pricing/")?"pricing":0===i.indexOf("/addons/")?"addons":0===i.indexOf("/industries/")?"industries":0===i.indexOf("/about/")?"about":0===i.indexOf("/contact/")?"contact":"home"}};